if ( ! defined( 'ABSPATH' ) ) {
	exit;
}

class CUAP_Auth {
	public function __construct() {
		add_shortcode( 'custom_register', array( $this, 'registration_form' ) );
		add_shortcode( 'custom_login', array( $this, 'login_form' ) );
		add_action( 'init', array( $this, 'handle_form_submission' ) );
	}

	public function registration_form() {
		if ( is_user_logged_in() ) {
			return '<p>You are already registered and logged in.</p>';
		}

		ob_start(); ?>
		<form method="post">
			<p>
				<label for="cuap_username">Username</label>
				<input type="text" name="cuap_username" id="cuap_username" required>
			</p>
			<p>
				<label for="cuap_email">Email</label>
				<input type="email" name="cuap_email" id="cuap_email" required>
			</p>
			<p>
				<label for="cuap_password">Password</label>
				<input type="password" name="cuap_password" id="cuap_password" required>
			</p>
			<?php wp_nonce_field( 'cuap_register_action', 'cuap_register_nonce' ); ?>
			<input type="hidden" name="cuap_action" value="register">
			<p><input type="submit" value="Register"></p>
		</form>
		<?php return ob_get_clean();
	}

	public function login_form() {
		if ( is_user_logged_in() ) {
			return '<p>You are already logged in.</p>';
		}

		ob_start(); ?>
		<form method="post">
			<p>
				<label for="cuap_login_username">Username or Email</label>
				<input type="text" name="cuap_login_username" id="cuap_login_username" required>
			</p>
			<p>
				<label for="cuap_login_password">Password</label>
				<input type="password" name="cuap_login_password" id="cuap_login_password" required>
			</p>
			<?php wp_nonce_field( 'cuap_login_action', 'cuap_login_nonce' ); ?>
			<input type="hidden" name="cuap_action" value="login">
			<p><input type="submit" value="Login"></p>
		</form>
		<?php return ob_get_clean();
	}

	public function handle_form_submission() {
		if ( empty( $_POST['cuap_action'] ) ) {
			return;
		}

		$action = sanitize_text_field( $_POST['cuap_action'] );

		if ( 'register' === $action ) {
			$this->process_registration();
		} elseif ( 'login' === $action ) {
			$this->process_login();
		}
	}

	private function process_registration() {
		if ( ! isset( $_POST['cuap_register_nonce'] ) || ! wp_verify_nonce( $_POST['cuap_register_nonce'], 'cuap_register_action' ) ) {
			return;
		}

		$username = sanitize_user( $_POST['cuap_username'] );
		$email    = sanitize_email( $_POST['cuap_email'] );
		$password = $_POST['cuap_password'];

		if ( username_exists( $username ) || email_exists( $email ) ) {
			wp_die( 'Username or email already exists.' );
		}

		$hashed_password = wp_hash_password( $password );

		$user_id = wp_insert_user( array(
			'user_login' => $username,
			'user_pass'  => $hashed_password,
			'user_email' => $email,
			'role'       => 'subscriber',
		) );

		if ( is_wp_error( $user_id ) ) {
			wp_die( 'Registration failed.' );
		}

		wp_set_current_user( $user_id );
		wp_set_auth_cookie( $user_id );
		wp_redirect( home_url() );
		exit;
	}

	private function process_login() {
		if ( ! isset( $_POST['cuap_login_nonce'] ) || ! wp_verify_nonce( $_POST['cuap_login_nonce'], 'cuap_login_action' ) ) {
			return;
		}

		$username_input = sanitize_text_field( $_POST['cuap_login_username'] );
		$password       = $_POST['cuap_login_password'];

		$user = get_user_by( 'login', $username_input );
		if ( ! $user ) {
			$user = get_user_by( 'email', $username_input );
		}

		if ( ! $user ) {
			wp_die( 'Invalid username/email.' );
		}

		if ( ! wp_check_password( $password, $user->user_pass, $user->ID ) ) {
			wp_die( 'Incorrect password.' );
		}

		wp_set_current_user( $user->ID );
		wp_set_auth_cookie( $user->ID );
		wp_redirect( home_url() );
		exit;
	}
}

new CUAP_Auth();